/**
 * Definition for a binary tree node.
 * struct TreeNode {
 *     int val;
 *     TreeNode *left;
 *     TreeNode *right;
 *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}
 * };
 */
class Codec {
public:
    // Encodes a tree to a single string.
    string serialize(TreeNode* root) {
        string data;
        serializeHelper(root, data);
        return data;
    }

    // Decodes your encoded data to tree.
    TreeNode* deserialize(string data) {
        if (data.empty()) return nullptr;
        int pos = 0;
        return deserializeHelper(data, pos, INT_MIN, INT_MAX);
    }

private:
    void serializeHelper(TreeNode* node, string& data) {
        if (!node) return;
        if (!data.empty()) data += ",";
        data += to_string(node->val);
        serializeHelper(node->left, data);
        serializeHelper(node->right, data);
    }

    TreeNode* deserializeHelper(const string& data, int& pos, int lower, int upper) {
        if (pos >= data.size()) return nullptr;
        int comma = data.find(',', pos);
        if (comma == string::npos) comma = data.size();
        int val = stoi(data.substr(pos, comma - pos));
        if (val < lower || val > upper) return nullptr;
        TreeNode* node = new TreeNode(val);
        pos = comma + 1;
        node->left = deserializeHelper(data, pos, lower, val - 1);
        node->right = deserializeHelper(data, pos, val + 1, upper);
        return node;
    }
};

